form:Form.form:Scripts:
		function OnLoad()
{
  //Cargo la Configuracion
  CFG   =new NomadXML(Ctrl("main").getResource("QRY_CFG"));
  CHLCFG=new NomadXML(Ctrl("main").getResource("QRY_CHILD"));

  //Mensaje Inicial de la Lista
  Ctrl("LIST").MsgEmply=(CFG.GetAttr("autoload")!="0"?"Cargando...":"Especifique algún criterio de búsqueda...");
  Ctrl("LIST_REG").SetXValue(CFG.GetAttr("autoload")!="0"?"Cargando...":"Especifique algún criterio de búsqueda.");

  //Modifico los Recursos
  ReplaceResource("QRY_IDS");
  ReplaceResource("QRY_IDS_LIST");
  ReplaceResource("QRY_IDS_METHOD");
  ReplaceResource("QRY_IDS_PARENT");

  //Actualizo el Titulo
  if ((CFG.GetAttr("RESOURCE-PARENT")!="") && (Ctrl("PARENT").GetXValue()!=""))
  {
    if (TIT==null)
      TIT=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_IDS_PARENT"), '<PARAM IDS="'+Ctrl("PARENT").GetXValue()+'"/>');

	  while(TIT!=null)
	  {
	    if (TIT.GetAttr("descr")!="")
	      Ctrl("PAR").SetXValue(" ("+TIT.GetAttr("descr")+")");
	    TIT=TIT.FirstChild();
	  }
  }

  //AGREGAR NUEVOS FILTROS	
	var filter = CFG.AddTailElement('FILTER');			
 	filter.SetAttr('name', 'f_desde'); 	
	filter = CFG.AddTailElement('FILTER');			
 	filter.SetAttr('name', 'f_hasta');
  filter = CFG.AddTailElement('FILTER');
  filter.SetAttr('name', 'l_current_user');

  //Cargo la Lista
  RefreshList(false);

  //Evento PosONLOAD
  PosOnLoad();
}


function EnabledButtons()
{
  var cur,f;
  if (Ctrl("LIST").GetXValue()=="" || Ctrl("LIST").TotalRow<=0)
  {
    CtrlEnabled("SHOW"  ,false);
    CtrlEnabled("ACCEPT",false);
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,false);
    CtrlEnabled("DELETE1",false);
    CtrlEnabled("DELETE2",false);
    CtrlEnabled("ADMIN" ,false);

    //Buscar que botones estan habilitados siempre
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
    {
      f=cur.GetAttrInt("flag");
      CtrlEnabled(cur.GetAttr("name"), (f==2?CheckEnabledButton(cur.GetAttr("name")):false));
    }
  } else
  if (Ctrl("LIST").GetSelectAttrValue("lock")!="")
  {
    CtrlEnabled("SHOW"  ,CheckEnabledButton("SHOW"));
    CtrlEnabled("ACCEPT",CheckEnabledButton("ACCEPT"));
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,Ctrl("LIST").GetSelectAttrValue("lock")=="2"?CheckEnabledButton("EDIT"):false);
    CtrlEnabled("DELETE1",false);
    CtrlEnabled("DELETE2",false);
    CtrlEnabled("ADMIN" ,(GetProxy().Admin()?CheckEnabledButton("ADMIN"):false));

    //Buscar que botones estan habilitados si esta bloqueado
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
    {
      f=cur.GetAttrInt("flag");
      CtrlEnabled(cur.GetAttr("name"), (f==2?CheckEnabledButton(cur.GetAttr("name")):false));
    }
  } else
  {
    CtrlEnabled("SHOW"  ,CheckEnabledButton("SHOW"));
    CtrlEnabled("ACCEPT",CheckEnabledButton("ACCEPT"));
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,CheckEnabledButton("EDIT"));    
    CtrlEnabled("ADMIN" ,(GetProxy().Admin()?CheckEnabledButton("ADMIN"):false));

    if(Ctrl("LIST").GetSelectAttrValue("l_eliminar_1")=="1")
    	CtrlEnabled("DELETE1",true);
    else
    	CtrlEnabled("DELETE1",false);
    if(Ctrl("LIST").GetSelectAttrValue("l_eliminar_2")=="1")
    	CtrlEnabled("DELETE2",true);
    else
    	CtrlEnabled("DELETE2",false);

    //Habilitar todos los botones
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
      CtrlEnabled(cur.GetAttr("name"), CheckEnabledButton(cur.GetAttr("name")));
  }
}


function delete_onclick()
{
	if (!confirm("¿Está seguro que desea eliminar la Novedad?")) return false;

  Ctrl("main").DoEvent("DELETE");
  return true;
}
